import{_ as t,c as e,o as a,N as l}from"./chunks/framework.627b6d20.js";const s="/ljtui2/渲染.png",o="/ljtui2/更新.png",n="/ljtui2/销毁.png",g=JSON.parse('{"title":"vue","description":"","frontmatter":{},"headers":[],"relativePath":"audition/vue/vue.md","lastUpdated":null}'),p={name:"audition/vue/vue.md"},r=l('<h1 id="vue" tabindex="-1">vue <a class="header-anchor" href="#vue" aria-label="Permalink to &quot;vue&quot;">​</a></h1><h2 id="vue生命周期" tabindex="-1">vue生命周期 <a class="header-anchor" href="#vue生命周期" aria-label="Permalink to &quot;vue生命周期&quot;">​</a></h2><table><thead><tr><th style="text-align:left;">Vue2(选项式API)</th><th style="text-align:center;">Vue3(setup)(选项式API)</th><th style="text-align:center;">描述</th></tr></thead><tbody><tr><td style="text-align:left;">beforeCreate</td><td style="text-align:center;">-</td><td style="text-align:center;">实例创建前</td></tr><tr><td style="text-align:left;">created</td><td style="text-align:center;">-</td><td style="text-align:center;">实例创建后</td></tr><tr><td style="text-align:left;">beforeMount</td><td style="text-align:center;">onBeforeMount</td><td style="text-align:center;">DOM挂载前调用</td></tr><tr><td style="text-align:left;">mounted</td><td style="text-align:center;">onMounted</td><td style="text-align:center;">DOM挂载完成调用</td></tr><tr><td style="text-align:left;">beforeUpdate</td><td style="text-align:center;">onBeforeUpdate</td><td style="text-align:center;">数据更新之前被调用</td></tr><tr><td style="text-align:left;">updated</td><td style="text-align:center;">onUpdated</td><td style="text-align:center;">数据更新之后被调用</td></tr><tr><td style="text-align:left;">beforeDestroy</td><td style="text-align:center;">onBeforeUnmount</td><td style="text-align:center;">组件销毁前调用</td></tr><tr><td style="text-align:left;">destroyed</td><td style="text-align:center;">onUnmounted</td><td style="text-align:center;">组件销毁完成调用</td></tr></tbody></table><h2 id="vue父子组件生命周期" tabindex="-1">vue父子组件生命周期 <a class="header-anchor" href="#vue父子组件生命周期" aria-label="Permalink to &quot;vue父子组件生命周期&quot;">​</a></h2><ol><li>渲染过程 父beforeCreate -&gt; 父created -&gt; 父beforeMount -&gt; 子beforeCreate -&gt; 子created -&gt; 子beforeMount -&gt; 子mounted -&gt; 父mounted <img src="'+s+'" alt="渲染"></li><li>更新过程 父beforeUpdate -&gt; 子beforeUpdate -&gt; 子updated -&gt; 父updated <img src="'+o+'" alt="更新"></li><li>销毁过程 父beforeDestroy -&gt; 子beforeDestroy -&gt; 子destroyed -&gt; 父destroyed <img src="'+n+`" alt="销毁"></li></ol><h3 id="注意" tabindex="-1">注意 <a class="header-anchor" href="#注意" aria-label="Permalink to &quot;注意&quot;">​</a></h3><p>如果子组件是异步组件的话它们的执行顺序会发生改变，会先执行完父组件的生命周期然后再执行子组件的生命周期</p><h2 id="v-if和v-show" tabindex="-1">v-if和v-show <a class="header-anchor" href="#v-if和v-show" aria-label="Permalink to &quot;v-if和v-show&quot;">​</a></h2><ol><li>v-if表示一个dom元素是否被创建，而v-show则是控制这个dom元素的display属性是否为none</li><li>一般在频繁切换状态的地方使用v-show,v-if则更适合条件不经常改变的场景，因为它切换开销相对较大</li></ol><h2 id="v-for和v-if优先级" tabindex="-1">v-for和v-if优先级 <a class="header-anchor" href="#v-for和v-if优先级" aria-label="Permalink to &quot;v-for和v-if优先级&quot;">​</a></h2><ol><li>开发过程中一般不建议同时将v-for和v-if放在一个标签中使用</li><li>Vue2中v-for的优先级会更高，所以会先执行循环，再进行v-if判断，所以这样就会导致无论需不需展示这个元素，都会先遍历整个列表</li><li>在Vue3中v-if的优先级会更高，但是当我们遍历一个数组的时候，根据数组中的某个元素进行v-if判断的时候就会报错，因为v-if会先执行此时还没有拿到这个数组。所以Vue3中依然不建议这样使用</li></ol><h2 id="说一下computed和watch" tabindex="-1">说一下computed和watch <a class="header-anchor" href="#说一下computed和watch" aria-label="Permalink to &quot;说一下computed和watch&quot;">​</a></h2><ol><li>computed是计算属性,当一个属性受一个或者多个属性影响的时候可以使用.watch是侦听器,当我们需要根据一个属性的变化而做出一些处理的时候,可以使用watch来对这个属性进行监听</li><li><strong>computed具有缓存的特点</strong>,即当它所依赖的属性发生改变的时候它才会重新执行内部逻辑.如下代码</li></ol><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">template</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;{{</span><span style="color:#A6ACCD;"> addSum </span><span style="color:#89DDFF;">}}&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;{{</span><span style="color:#A6ACCD;"> addSum </span><span style="color:#89DDFF;">}}&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">    </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;{{</span><span style="color:#A6ACCD;"> addSum </span><span style="color:#89DDFF;">}}&lt;/</span><span style="color:#F07178;">div</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">template</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">script</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">setup</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">import </span><span style="color:#89DDFF;">{</span><span style="color:#A6ACCD;"> computed</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> ref</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> watch </span><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;"> from &quot;vue&quot;;</span></span>
<span class="line"><span style="color:#A6ACCD;">const a = ref(1)</span></span>
<span class="line"><span style="color:#A6ACCD;">const b = ref(2)</span></span>
<span class="line"><span style="color:#A6ACCD;">let addSum = computed(() =&gt; </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">    console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">内部逻辑执行</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"><span style="color:#A6ACCD;">    return a</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">value </span><span style="color:#89DDFF;">+</span><span style="color:#A6ACCD;"> b</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">value</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">script</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><p>页面多次使用addSum,但是只会打印一次&quot;内部逻辑执行&quot;</p><ol start="3"><li>侦听器可以检测某个响应式数据的变化并执行副作用，常见用法是传递一个函数，执行副作用，watch没有返回值，但可以执行异步操作等复杂逻辑。（一般用来请求接口）</li><li>watch在页面首次加载的时候默认不会执行,需要设置immediate:true首次才会执行监听</li><li>watch默认只监听一层数据,不监听多层数据里属性的变化,需要设置deep:true才会进行深度监听</li></ol><h3 id="computed和methods的区别" tabindex="-1">computed和methods的区别？ <a class="header-anchor" href="#computed和methods的区别" aria-label="Permalink to &quot;computed和methods的区别？&quot;">​</a></h3><p>computed和methods的差异是它具备缓存性，如果依赖项不变时不会重新计算。</p><h3 id="computed和watch使用场景" tabindex="-1">computed和watch使用场景 <a class="header-anchor" href="#computed和watch使用场景" aria-label="Permalink to &quot;computed和watch使用场景&quot;">​</a></h3><ol><li>计算属性computed常用场景是简化在template模板中的复杂表达式，模板中出现太多逻辑判断会造成模板不易维护。</li><li>computed不支持异步</li><li>都是以 Vue 的依赖追踪机制为基础，当某个依赖数据发生变化时，所有依赖这个数据的相关数据或函数都会自动发生变化或调用。</li><li>侦听器Watch常用场景是状态变化之后做一些异步操作。</li><li>有异步请求的用Wach，其他情况能用计算属性就首选计算属性。</li></ol><h3 id="computed的原理" tabindex="-1">computed的原理 <a class="header-anchor" href="#computed的原理" aria-label="Permalink to &quot;computed的原理&quot;">​</a></h3><p>computed 的实现是基于 Watcher 实例对象(被观察者)的</p><h3 id="computed的两种定义方式" tabindex="-1">computed的两种定义方式 <a class="header-anchor" href="#computed的两种定义方式" aria-label="Permalink to &quot;computed的两种定义方式&quot;">​</a></h3><p>一种是方法，另一种是 get，set 属性。而且，其内部监听的对象必须是已经定义响应式的属性，比如 data 的属性、vuex 的属性。</p><h4 id="computed属性的初始化" tabindex="-1">computed属性的初始化 <a class="header-anchor" href="#computed属性的初始化" aria-label="Permalink to &quot;computed属性的初始化&quot;">​</a></h4><ol><li>vue 在创建 computed 属性时候，遍历computed属性，为每个computed属性都创建一个watcher,对每个computed属性进行get劫持</li><li>get劫持是最关键的步骤 <ol><li>将computed-watcher添加到data属性值的订阅者队列。（<strong>在前）</strong></li><li>将render-watcher添加到data属性值的订阅者队列。<strong>（在后）</strong></li></ol></li><li>这样就能实现，当data属性值变化后： <ol><li>render函数执行</li><li>computed属性函数执行并返回新执行结果</li></ol></li></ol><p>vue 在创建 computed 属性时候，会循环所有计算属性，每一个计算属性会创建一个 watcher，(并且在通过 defineProperty(vue2),proxy(vue3) 定义监听)，在 get 中，计算属性工作是做依赖收集，在 set 中，计算属性重要工作是重新执行计算方法，这里需要多补充一句，因为 computed 是懒执行，也就是说第一次初始化之后，便不会执行计算，下一次变更执行重新计算是在 set 中。</p><h3 id="依赖收集的时机" tabindex="-1">依赖收集的时机 <a class="header-anchor" href="#依赖收集的时机" aria-label="Permalink to &quot;依赖收集的时机&quot;">​</a></h3><p>computed 收集时机和 data 一样，是在组件挂载前，但是其收集对象是自己属性对应的 watch，而 data 本身所有数据对应一个 watch。</p>`,29),c=[r];function d(i,u,h,y,D,m){return a(),e("div",null,c)}const f=t(p,[["render",d]]);export{g as __pageData,f as default};
